START TRANSACTION;
CREATE TABLE "Author" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "FirstName" text NOT NULL,
    "LastName" text NOT NULL,
    "Biography" text,
    CONSTRAINT "PK_Author" PRIMARY KEY ("Id")
);

CREATE TABLE "AuthorBook" (
    "AuthorsId" integer NOT NULL,
    "BooksId" integer NOT NULL,
    CONSTRAINT "PK_AuthorBook" PRIMARY KEY ("AuthorsId", "BooksId"),
    CONSTRAINT "FK_AuthorBook_Author_AuthorsId" FOREIGN KEY ("AuthorsId") REFERENCES "Author" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_AuthorBook_Books_BooksId" FOREIGN KEY ("BooksId") REFERENCES "Books" ("Id") ON DELETE CASCADE
);

CREATE INDEX "IX_AuthorBook_BooksId" ON "AuthorBook" ("BooksId");


-- Backfill: create Unknown Author once
INSERT INTO "Author" ("FirstName", "LastName", "Biography")
SELECT 'Unknown', 'Author', 'Auto-created during V002 migration to satisfy required author relationship'
WHERE NOT EXISTS (
  SELECT 1 FROM "Author" WHERE "FirstName"='Unknown' AND "LastName"='Author'
);

-- Backfill: attach Unknown Author to all books without any author
INSERT INTO "AuthorBook" ("AuthorsId", "BooksId")
SELECT a."Id", b."Id"
FROM "Books" b
JOIN "Author" a ON a."FirstName"='Unknown' AND a."LastName"='Author'
WHERE NOT EXISTS (
  SELECT 1 FROM "AuthorBook" ba WHERE ba."BooksId" = b."Id"
);

